scwin.txt_fileSiz = "";
scwin.txt_fileSavePath = "";
scwin.onpageload = function () {
  scwin.userId = $c.ses.getUserId();
  scwin.argObject = $c.data.getParameter($p);
  if (scwin.argObject == null) {
    scwin.argObject = {};
  }
  dma_login_query_condition.set("fixEmpNo", scwin.userId);
  scwin.f_OnLoad();
};
scwin.f_OnLoad = async function () {
  await $c.sbm.execute($p, sbm_login);
  $c.gus.cfDisableObjects($p, [txt_fixWrkPlNm, ica_rglintChkExpireDt, txt_eqClssNm, txt_eqKndNm, txt_eqModelNm, ica_rglintInspExpireDt, txt_acctDeptNm, txt_assgnLobranNm, txt_damageWrongTyp, txt_taxNo, txt_slipNo, em_wrkPlanDt, em_adptWages, ica_mntnInspExpireDt, em_partAmt, em_wages, em_totAmt, em_vatAmt]);
  $c.gus.cfSetIMEModeActiveObjects($p, [txt_vehclNo]);
  if (scwin.argObject.fixWrkNo != null && scwin.argObject.fixWrkNo != "") {
    em_fixWrkPlCd.setValue(scwin.argObject.fixWrkPlCd);
    em_fixWrkNo.setValue(scwin.argObject.fixWrkNo);
    await scwin.f_Retrieve();
    scwin.f_ctrlGrdEnable(false);
    scwin.f_ctrlApplyFixWorkStandardBtn(true);
    scwin.f_ctrlGrdBtn(true);
    scwin.f_ioNesYn();
    scwin.f_setAdjustment();
  } else {
    scwin.cvNNew = true;
    sbm_retrieve.action = "/ps.eq.fixwrkmgnt.fixwrkmgnt.RetrieveFixWorkCMD.do";
    await $c.sbm.execute($p, sbm_retrieve);
    ds_fix_work.set("homeClsCd", scwin.argObject.homeClsCd || "");
    ds_fix_work.set("travelDtc", "0");
    ds_fix_work.set("applyFixWorkStandardYn", "0");
    em_fixWrkPlCd.setValue(scwin.argObject.fixWrkPlCd || "");
    scwin.f_openCommonPopUp(1, em_fixWrkPlCd.getValue(), '', 'T', 'T');
    em_eqCd.setValue(scwin.argObject.eqCd || "");
    txt_vehclNo.setValue(scwin.argObject.vehclNo || "");
    $c.gus.cfEnableObjects($p, [btn_Edit, btn_SaveTemporary, btn_Save, btn_Del, btn_Close]);
    scwin.f_ctrlApplyFixWorkStandardBtn(false);
    scwin.f_ctrlGrdBtn(false);
    btn_Edit.setDisabled(true);
    btn_Del.setDisabled(true);
    if (scwin.argObject.fixKndCd != null && scwin.argObject.fixKndCd != "") {
      lux_fixKndCd.setValue(scwin.argObject.fixKndCd);
    } else {
      lux_fixKndCd.setSelectedIndex(0);
    }
    if (scwin.argObject.selfOutordClsCd != null && scwin.argObject.selfOutordClsCd != "") {
      lux_selfOutordClsCd.setValue(scwin.argObject.selfOutordClsCd);
    } else {
      lux_selfOutordClsCd.setSelectedIndex(0);
    }
    lux_fixCauseCd.setSelectedIndex(0);
    lux_fixCatCd.setSelectedIndex(0);
    $c.gus.cfDisableObjects($p, [txt_accdRecptNo, em_circulPartCd, txt_circulPartNm, img_accdRecptNo]);
    lux_fixWrkStsCd.setValue("R");
    chk_ioNesYn.setValue("1");
    scwin.f_ioNesYn();
    em_fixWrkPlCd.setFocus();
    if (em_eqCd.getValue() != "" && txt_vehclNo.getValue() != "") {
      scwin.f_openCommonPopUp(2, em_eqCd.getValue(), txt_vehclNo.getValue(), 'T', 'T');
    }
  }
  scwin.f_selfOutordCls();
  ds_fix_work.set("applyFixWorkStandardYn", "0");
  if (!(scwin.argObject.homeClsCd == "TR" && em_fixWrkPlCd.getValue() != "201")) {
    if (ds_login.get("fixEmpClsCd") == "2") {
      btn_Save.setDisabled(true);
    }
  }
  scwin.repFixWrkPlCd = await scwin.f_retrieveRepFixWrkPl();
};
scwin.f_Retrieve = async function () {
  let strAction = "/ps.eq.fixwrkmgnt.fixwrkmgnt.RetrieveFixWorkCMD.do";
  dma_fix_work_re.set("fixWrkPlCd", em_fixWrkPlCd.getValue());
  dma_fix_work_re.set("fixWrkNo", em_fixWrkNo.getValue());
  sbm_retrieve.action = strAction;
  await $c.sbm.execute($p, sbm_retrieve);
  scwin.cvFixWrkStsCd = ds_fix_work.get("fixWrkStsCd");
  lux_fixWrkStsCd.setValue(ds_fix_work.get("fixWrkStsCd"));
  ds_fix_work.set("applyFixWorkStandardYn", "0");
  $c.gus.cfEnableObjects($p, [btn_Edit, btn_SaveTemporary, btn_Save, btn_Del, btn_Close]);
  $c.gus.cfDisableObjects($p, [btn_Save, btn_SaveTemporary]);
  $c.gus.cfDisableKeyData($p);
  let wrkStDtVal = ica_wrkStDt.getValue();
  let wrkEndDtVal = ica_wrkEndDt.getValue();
  if (wrkStDtVal != "" && wrkEndDtVal != "") {
    em_needDt.setValue($c.date.diffDate($p, wrkStDtVal, wrkEndDtVal));
  }
};
scwin.sbm_retrieve_submitdone = function (e) {
  scwin.f_setAdjustment();
};
scwin.sbm_retrieve_submiterror = function (e) {
  $c.gus.cfShowError($p, e);
};
scwin.sbm_applyFixWorkStandard_submitdone = function (e) {};
scwin.sbm_applyFixWorkStandard_submiterror = function (e) {
  $c.gus.cfShowError($p, e);
};
scwin.sbm_applyFixWorkUnit_submitdone = function (e) {};
scwin.sbm_applyFixWorkUnit_submiterror = function (e) {
  $c.gus.cfShowError($p, e);
};
