scwin.sbm_login_submiterror = function (e) {
  $c.gus.cfShowError($p, e);
};
scwin.sbm_repFixWrkPl_submitdone = function (e) {};
scwin.sbm_repFixWrkPl_submiterror = function (e) {
  $c.gus.cfShowError($p, e);
};
scwin.sbm_save_submitdone = async function (e) {
  if (scwin.cvDelete == true) {
    await $c.gus.cfAlertMsg($p, MSG_CM_INF_004);
  } else {
    await $c.gus.cfAlertMsg($p, MSG_CM_INF_001);
  }
  scwin.saveSuccess = true;
};
scwin.sbm_save_submiterror = function (e) {
  scwin.saveSuccess = false;
  $c.gus.cfShowError($p, e);
};
scwin.btn_Edit_onclick = function (e) {
  scwin.f_Update();
};
scwin.btn_SaveTemporary_onclick = function (e) {
  scwin.f_SaveTemporary();
};
scwin.btn_Save_onclick = function (e) {
  scwin.f_Save();
};
scwin.btn_Del_onclick = function (e) {
  scwin.f_Delete();
};
scwin.btn_Close_onclick = function (e) {
  $c.win.closePopup($p);
};
scwin.f_Update = async function () {
  let wrkEndDtVal = ica_wrkEndDt.getValue();
  if (wrkEndDtVal != "") {
    if ($c.gus.cfJobCloseYN($p, "CUR", wrkEndDtVal.substring(0, 6), "00", "EQ01", scwin.repFixWrkPlCd, null, "N") == 2) {
      await $c.win.alert($p, wrkEndDtVal.substring(0, 4) + "년 " + wrkEndDtVal.substring(4, 6) + "월의 마감이 이미 완료되었습니다.");
      return;
    }
  }
  scwin.cvUpdate = true;
  $c.gus.cfEnableKeyData($p);
  $c.gus.cfDisableKey($p);
  $c.gus.cfEnableObjects($p, [btn_Edit, btn_SaveTemporary, btn_Save, btn_Del, btn_Close]);
  $c.gus.cfDisableObjects($p, [btn_Edit, em_partAmt, em_wages, em_totAmt, em_vatAmt]);
  scwin.f_selfOutordCls();
  ds_fix_work.set("applyFixWorkStandardYn", "0");
  scwin.f_ctrlFixKndCd();
  scwin.f_ctrlGrdBtn(false);
  if (scwin.cvFixWrkStsCd == "C") {
    $c.gus.cfDisableObjects($p, [btn_SaveTemporary]);
    scwin.f_ctrlApplyFixWorkStandardBtn(true);
    $c.gus.cfDisableObjects($p, [ica_wrkEndDt, em_wrkEndHh]);
  } else if (scwin.cvFixWrkStsCd == "I") {
    scwin.f_ctrlApplyFixWorkStandardBtn(false);
  } else {
    scwin.f_ctrlApplyFixWorkStandardBtn(true);
  }
  scwin.f_ioNesYn();
  $c.gus.cfDisableObjects($p, [em_wrkPlanDt, lux_selfOutordClsCd]);
  scwin.f_ctrlGrdEnable(true);
};
