scwin.f_calcWrkTime = function () {
  for (let i = 0; i < ds_fix_work_unit.getRowCount(); i++) {
    ds_fix_work_unit.setCellData(i, "wrkHhCnt", 0);
  }
  for (let i = 0; i < ds_fix_driver.getRowCount(); i++) {
    if (ds_fix_driver.getRowStatus(i) == "D") continue;
    let unitNo = ds_fix_driver.getCellData(i, "fixWrkUnitNo");
    let unitIdx = -1;
    for (let j = 0; j < ds_fix_work_unit.getRowCount(); j++) {
      if (ds_fix_work_unit.getCellData(j, "fixWrkUnitNo") == unitNo) {
        unitIdx = j;
        break;
      }
    }
    if (unitIdx >= 0) {
      let cur = parseFloat(ds_fix_work_unit.getCellData(unitIdx, "wrkHhCnt") || "0");
      let add = parseFloat(ds_fix_driver.getCellData(i, "wrkHhCnt") || "0");
      ds_fix_work_unit.setCellData(unitIdx, "wrkHhCnt", cur + add);
    }
  }
};
scwin.f_setIntendDt = function () {
  if (em_wrkIntendDt.getValue() == "" && ica_wrkStDt.getValue() != "") {
    em_wrkIntendDt.setValue(ica_wrkStDt.getValue());
  }
  if (em_endIntendDt.getValue() == "" && ica_wrkEndDt.getValue() != "") {
    em_endIntendDt.setValue(ica_wrkEndDt.getValue());
  }
};
scwin.f_setAdjustment = function () {
  let partAmt = 0;
  let vatAmt = 0;
  for (let row = 0; row < ds_fix_work_parts.getRowCount(); row++) {
    partAmt += parseInt(ds_fix_work_parts.getCellData(row, "totAmt") || "0");
  }
  em_partAmt.setValue(partAmt);
  if (lux_selfOutordClsCd.getValue() == "IN") {
    let wages = 0;
    for (let row = 0; row < ds_fix_work_unit.getRowCount(); row++) {
      let adptWagesVal = parseInt(em_adptWages.getValue() || "0");
      let wrkHhCntVal = parseInt(ds_fix_work_unit.getCellData(row, "wrkHhCnt") || "0");
      if (adptWagesVal != 0 && wrkHhCntVal != 0) {
        wages += adptWagesVal * wrkHhCntVal;
      }
    }
    em_wages.setValue(wages);
    em_totAmt.setValue(parseInt(em_partAmt.getValue() || "0"));
  } else {
    let wages = 0;
    for (let row = 0; row < ds_fix_work_unit.getRowCount(); row++) {
      let qtyVal = parseInt(ds_fix_work_unit.getCellData(row, "qty") || "0");
      let uprVal = parseInt(ds_fix_work_unit.getCellData(row, "upr") || "0");
      if (qtyVal != 0 && uprVal != 0) {
        ds_fix_work_unit.setCellData(row, "bilgWages", qtyVal * uprVal);
        ds_fix_work_unit.setCellData(row, "vatAmt", ds_fix_work_unit.getCellData(row, "bilgWages") / 10);
      }
      wages += parseInt(ds_fix_work_unit.getCellData(row, "bilgWages") || "0");
      vatAmt += parseInt(ds_fix_work_unit.getCellData(row, "vatAmt") || "0");
    }
    em_wages.setValue(wages);
    em_totAmt.setValue(parseInt(em_wages.getValue() || "0") + parseInt(em_partAmt.getValue() || "0"));
  }
  if (em_totAmt.getValue() != "") {
    em_vatAmt.setValue(parseFloat(em_totAmt.getValue() || "0") / 10);
    if (lux_selfOutordClsCd.getValue() == "OT" && vatAmt != 0) {
      em_vatAmt.setValue(vatAmt);
    }
  }
};
