scwin.f_vatChk = async function () {
  let spplyAmt = parseInt(em_wages.getValue() || "0");
  let vatAmtVal = parseInt(em_vatAmt.getValue() || "0");
  let chkSpplyAmt = vatAmtVal * 10;
  let tmpAmt = Math.round(spplyAmt * 0.1);
  let absAmt = Math.abs(chkSpplyAmt - spplyAmt);
  if (absAmt > 50) {
    await $c.win.alert($p, "입력한 부가세액은 공급금액의 10%금액과 차이 ±50원 이내이어햐 합니다.(정상부가세액 : " + tmpAmt + ")");
    return true;
  } else {
    return false;
  }
};
